import { RouteProp, useNavigation, useRoute } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useContext, useEffect, useMemo, useRef, useState } from 'react';
import {
  ActivityIndicator,
  Animated,
  Linking,
  Pressable,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  View
} from 'react-native';
import { AuthContext } from '../../App';
import OrderStatusTracker from '../components/OrderStatusTracker';
import { formatCurrency, formatOrderNumber } from '../data/orderModule';
import { RootStackParamList } from '../navigation/AppNavigator';
import { fetchCustomerOrders, OrderRecord, subscribeToOrder } from '../services/firebaseService';

type RouteProps = RouteProp<RootStackParamList, 'OrderTracking'>;
type NavigationProp = NativeStackNavigationProp<RootStackParamList>;

const deliveryContact = {
  name: 'Water Delivery Team',
  phone: '+91 99000 02222'
};

const OrderTrackingScreen = () => {
  const route = useRoute<RouteProps>();
  const navigation = useNavigation<NavigationProp>();
  const { profile } = useContext(AuthContext);
  const [order, setOrder] = useState<OrderRecord | null>(null);
  const [loading, setLoading] = useState(true);
  const moveX = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    Animated.loop(
      Animated.sequence([
        Animated.timing(moveX, { toValue: 210, duration: 2200, useNativeDriver: true }),
        Animated.timing(moveX, { toValue: 0, duration: 0, useNativeDriver: true })
      ])
    ).start();
  }, [moveX]);

  useEffect(() => {
    let unsubscribe: undefined | (() => void);
    let active = true;

    const loadOrder = async () => {
      const explicitOrderId = route.params?.orderId;
      if (explicitOrderId) {
        unsubscribe = subscribeToOrder(explicitOrderId, (nextOrder) => {
          if (active) {
            setOrder(nextOrder);
            setLoading(false);
          }
        });
        return;
      }

      if (!profile?.uid) {
        setOrder(null);
        setLoading(false);
        return;
      }

      const orders = await fetchCustomerOrders(profile.uid).catch(() => []);
      const activeOrder =
        orders.find((item) => item.status !== 'delivered' && item.status !== 'cancelled') ?? orders[0] ?? null;
      setOrder(activeOrder);
      setLoading(false);

      if (activeOrder?.id) {
        unsubscribe = subscribeToOrder(activeOrder.id, (nextOrder) => {
          if (active) {
            setOrder(nextOrder);
          }
        });
      }
    };

    loadOrder();
    return () => {
      active = false;
      unsubscribe?.();
    };
  }, [profile?.uid, route.params?.orderId]);

  const etaText = useMemo(() => order?.expectedDeliveryTime || 'Today, 30-45 min', [order?.expectedDeliveryTime]);

  if (loading) {
    return (
      <SafeAreaView style={styles.loaderContainer}>
        <ActivityIndicator size="large" color="#0D8DD8" />
      </SafeAreaView>
    );
  }

  if (!order) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.emptyCard}>
          <Text style={styles.emptyTitle}>No order available for tracking</Text>
          <Text style={styles.emptyText}>Place a new order and tracking will appear here.</Text>
          <Pressable style={styles.primaryButton} onPress={() => navigation.navigate('NewOrder')}>
            <Text style={styles.primaryButtonText}>Book Water Now</Text>
          </Pressable>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <View style={styles.heroCard}>
          <Text style={styles.heroLabel}>Order tracking</Text>
          <Text style={styles.heroTitle}>{formatOrderNumber(order)}</Text>
          <Text style={styles.heroText}>Your delivery is moving step by step. We update this page as the order changes.</Text>
          <View style={styles.heroMetaRow}>
            <Text style={styles.heroMetaText}>{order.quantity} cans</Text>
            <Text style={styles.heroMetaText}>{formatCurrency(order.totalAmount)}</Text>
          </View>
        </View>

        <View style={styles.animationCard}>
          <Text style={styles.sectionTitle}>Delivery progress</Text>
          <View style={styles.trackBar}>
            <Animated.View style={[styles.movingDrop, { transform: [{ translateX: moveX }] }]} />
          </View>
          <Text style={styles.animationText}>Water delivery is moving towards your home.</Text>
        </View>

        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>Live order steps</Text>
          <OrderStatusTracker status={order.status} />
        </View>

        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>Delivery details</Text>
          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Customer address</Text>
            <Text style={styles.detailValue}>{order.address}</Text>
          </View>
          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Ordered quantity</Text>
            <Text style={styles.detailValue}>{order.quantity} cans</Text>
          </View>
          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Estimated arrival time</Text>
            <Text style={styles.detailValue}>{etaText}</Text>
          </View>
          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Payment method</Text>
            <Text style={styles.detailValue}>{order.paymentMethod}</Text>
          </View>
        </View>

        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>Need help?</Text>
          <Text style={styles.helpText}>Call or message the delivery boy / owner for quick updates.</Text>
          <View style={styles.contactCard}>
            <Text style={styles.contactName}>{deliveryContact.name}</Text>
            <Text style={styles.contactPhone}>{deliveryContact.phone}</Text>
          </View>
          <View style={styles.actionRow}>
            <Pressable style={styles.primaryButton} onPress={() => Linking.openURL(`tel:${deliveryContact.phone}`)}>
              <Text style={styles.primaryButtonText}>Call</Text>
            </Pressable>
            <Pressable style={styles.secondaryButton} onPress={() => Linking.openURL(`sms:${deliveryContact.phone}`)}>
              <Text style={styles.secondaryButtonText}>Message</Text>
            </Pressable>
          </View>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F2F9FF'
  },
  loaderContainer: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#F2F9FF'
  },
  content: {
    padding: 18,
    paddingBottom: 30
  },
  heroCard: {
    backgroundColor: '#10324A',
    borderRadius: 28,
    padding: 20
  },
  heroLabel: {
    color: '#AEE6FF',
    fontSize: 12,
    fontWeight: '800',
    textTransform: 'uppercase'
  },
  heroTitle: {
    marginTop: 10,
    color: 'white',
    fontSize: 30,
    fontWeight: '900'
  },
  heroText: {
    marginTop: 10,
    color: '#D1E7F5',
    fontSize: 14,
    lineHeight: 21
  },
  heroMetaRow: {
    marginTop: 16,
    flexDirection: 'row',
    justifyContent: 'space-between'
  },
  heroMetaText: {
    color: 'white',
    fontSize: 15,
    fontWeight: '800'
  },
  animationCard: {
    marginTop: 16,
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 18
  },
  sectionCard: {
    marginTop: 16,
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 18
  },
  sectionTitle: {
    color: '#10324A',
    fontSize: 19,
    fontWeight: '800'
  },
  trackBar: {
    marginTop: 16,
    height: 14,
    borderRadius: 999,
    backgroundColor: '#E3F0FF',
    overflow: 'hidden',
    justifyContent: 'center'
  },
  movingDrop: {
    width: 24,
    height: 24,
    borderRadius: 12,
    backgroundColor: '#0D8DD8'
  },
  animationText: {
    marginTop: 10,
    color: '#5E788C',
    fontSize: 13
  },
  detailRow: {
    marginTop: 14
  },
  detailLabel: {
    color: '#6D8699',
    fontSize: 12,
    fontWeight: '700',
    textTransform: 'uppercase'
  },
  detailValue: {
    marginTop: 6,
    color: '#10324A',
    fontSize: 15,
    fontWeight: '800',
    lineHeight: 22
  },
  helpText: {
    marginTop: 8,
    color: '#5E788C',
    fontSize: 14,
    lineHeight: 20
  },
  contactCard: {
    marginTop: 14,
    borderRadius: 20,
    backgroundColor: '#F6FBFF',
    padding: 14
  },
  contactName: {
    color: '#10324A',
    fontSize: 16,
    fontWeight: '800'
  },
  contactPhone: {
    marginTop: 6,
    color: '#5E788C',
    fontSize: 14
  },
  actionRow: {
    marginTop: 14,
    flexDirection: 'row',
    gap: 10
  },
  primaryButton: {
    flex: 1,
    backgroundColor: '#0D8DD8',
    borderRadius: 20,
    paddingVertical: 15,
    alignItems: 'center'
  },
  primaryButtonText: {
    color: 'white',
    fontSize: 16,
    fontWeight: '900'
  },
  secondaryButton: {
    flex: 1,
    backgroundColor: '#EAF7FF',
    borderRadius: 20,
    paddingVertical: 15,
    alignItems: 'center'
  },
  secondaryButtonText: {
    color: '#0D63A8',
    fontSize: 16,
    fontWeight: '800'
  },
  emptyCard: {
    margin: 18,
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 20
  },
  emptyTitle: {
    color: '#10324A',
    fontSize: 22,
    fontWeight: '800'
  },
  emptyText: {
    marginTop: 10,
    color: '#6D8699',
    fontSize: 14,
    lineHeight: 21
  }
});

export default OrderTrackingScreen;
